SectionAreaConditionFormulas.BackgroundColor:
// This conditional formatting formula must return one of the following Color Constants:
// 
// Color (red, green, blue)
// crBlack
// crMaroon
// crGreen
// crOlive
// crNavy
// crPurple
// crTeal
// crSilver
// crRed
// crLime
// crYellow
// crBlue
// crFuchsia
// crAqua
// crWhite
// crNoColor
// 
If (RecordNumber Mod 2 = 0) Then
    Color(220,220,220)
Else
    crWhite;
